 57→func (s *apiServer) UpdateCurrentUser(w http.ResponseWriter, r *http.Request) {
 58→	claims := auth.ClaimsFromContext(r.Context())
 59→	if claims == nil {
 60→		writeError(w, http.StatusUnauthorized, "unauthorized", "not authenticated")
 61→		return
 62→	}
 63→
 64→	if s.users == nil {
 65→		writeError(w, http.StatusNotImplemented, "not_implemented", "auth not enabled")
 66→		return
 67→	}
 68→
 69→	var req api.UpdateUserRequest
 70→	if err := decodeBody(r, &req); err != nil {
 71→		writeError(w, http.StatusBadRequest, "bad_request", "invalid request body")
 72→		return
 73→	}
 74→
 75→	user, err := s.users.Get(r.Context(), claims.Subject)
 76→	if err != nil {
 77→		writeError(w, http.StatusNotFound, "not_found", "user not found")
 78→		return
 79→	}
 80→
 81→	if req.DisplayName != nil {
 82→		user.DisplayName = *req.DisplayName
 83→	}
 84→
 85→	user.UpdatedAt = time.Now().UTC()
 86→	if err := s.users.Update(r.Context(), user); err != nil {
 87→		writeError(w, http.StatusInternalServerError, "internal", "failed to update user")
 88→		return
 89→	}
 90→
 91→	writeJSON(w, http.StatusOK, userToAPI(user))
 92→}
