 94→func (s *apiServer) UpdateCurrentEnterprise(w http.ResponseWriter, r *http.Request) {
 95→	claims := auth.ClaimsFromContext(r.Context())
 96→	if claims == nil {
 97→		writeError(w, http.StatusUnauthorized, "unauthorized", "not authenticated")
 98→		return
 99→	}
100→
101→	if s.enterprises == nil {
102→		writeError(w, http.StatusNotImplemented, "not_implemented", "auth not enabled")
103→		return
104→	}
105→
106→	if claims.Role != string(model.UserRoleOwner) && claims.Role != string(model.UserRoleAdmin) {
107→		writeError(w, http.StatusForbidden, "forbidden", "owner or admin role required")
108→		return
109→	}
110→
111→	var req api.UpdateEnterpriseRequest
112→	if err := decodeBody(r, &req); err != nil {
113→		writeError(w, http.StatusBadRequest, "bad_request", "invalid request body")
114→		return
115→	}
116→
117→	ent, err := s.enterprises.Get(r.Context(), claims.EnterpriseID)
118→	if err != nil {
119→		writeError(w, http.StatusNotFound, "not_found", "enterprise not found")
120→		return
121→	}
122→
123→	if req.Name != nil {
124→		ent.Name = *req.Name
125→	}
126→	if req.BillingEmail != nil {
127→		ent.BillingEmail = string(*req.BillingEmail)
128→	}
129→	if req.SsoRequired != nil {
130→		ent.SSORequired = *req.SsoRequired
131→	}
132→	if req.AllowedAuthProviders != nil {
133→		ent.AllowedAuthProviders = *req.AllowedAuthProviders
134→	}
135→	if req.AllowedEmailDomains != nil {
136→		ent.AllowedEmailDomains = *req.AllowedEmailDomains
137→	}
138→
139→	ent.UpdatedAt = time.Now().UTC()
140→	if err := s.enterprises.Update(r.Context(), ent); err != nil {
141→		writeError(w, http.StatusInternalServerError, "internal", "failed to update enterprise")
142→		return
143→	}
144→
145→	writeJSON(w, http.StatusOK, enterpriseToAPI(ent))
146→}
