			url.QueryEscape(stateParam),
		)
		h.log.Info("relaying OAuth callback to originating host", "host", originatingHost, "provider", providerName)
		http.Redirect(w, r, relayURL, http.StatusFound)
		return
	}

	// Validate CSRF state.

