package config

import (
	"fmt"
	"os"
	"strings"
	"time"
)

// AuthConfig holds authentication configuration, loaded from environment
// variables. Secrets (client secrets, signing keys) must not be stored in
// the YAML config file.
type AuthConfig struct {
	// DatabaseURL is the PostgreSQL connection string.
	// Env: AILERON_DATABASE_URL
	DatabaseURL string

	// JWTSigningKey is the HMAC key for signing access tokens.
	// Env: AILERON_JWT_SIGNING_KEY
	JWTSigningKey string

	// JWTIssuer is the "iss" claim in issued tokens.
	// Env: AILERON_JWT_ISSUER (default: "aileron")
	JWTIssuer string

	// AccessTokenTTL is the lifetime of access tokens.
	// Env: AILERON_ACCESS_TOKEN_TTL (default: "15m")
	AccessTokenTTL time.Duration

	// RefreshTokenTTL is the lifetime of refresh tokens.
	// Env: AILERON_REFRESH_TOKEN_TTL (default: "168h" = 7 days)
	RefreshTokenTTL time.Duration

	// UIRedirectURL is where users are sent after successful auth.
	// Env: AILERON_UI_REDIRECT_URL (default: "/")
	UIRedirectURL string

	// AutoVerifyEmail skips email verification on signup, activating
	// accounts immediately. For development and CI only.
	// Env: AILERON_AUTO_VERIFY_EMAIL
	AutoVerifyEmail bool

	// Google OAuth configuration.
	GoogleClientID     string // Env: GOOGLE_CLIENT_ID
	GoogleClientSecret string // Env: GOOGLE_CLIENT_SECRET

	// GitHub OAuth configuration.
	GitHubClientID     string // Env: GITHUB_OAUTH_CLIENT_ID
	GitHubClientSecret string // Env: GITHUB_OAUTH_CLIENT_SECRET

	// OAuthCallbackBaseURL, when set, is used as the base URL for all OAuth
	// callback redirects instead of deriving it from the incoming request host.
	// Set this to a stable domain (e.g. "https://auth.withaileron.ai") so that
	// OAuth providers only need one registered redirect URI regardless of how
	// many branch deployments exist.
	// Env: AILERON_OAUTH_CALLBACK_BASE_URL
	OAuthCallbackBaseURL string

	// TrustedOrigins is a comma-separated list of origin patterns that are
	// allowed as relay targets when OAuthCallbackBaseURL is set. Patterns may
	// use a leading "*." wildcard to match any subdomain
	// (e.g. "*.up.railway.app"). Exact hostnames are also supported.
	// Env: AILERON_TRUSTED_ORIGINS
	TrustedOrigins []string
}

// LoadAuthConfig loads auth configuration from environment variables.
// It returns an error only if required fields are missing when auth is
// enabled (indicated by AILERON_DATABASE_URL being set).
func LoadAuthConfig() (*AuthConfig, error) {
	cfg := &AuthConfig{
		DatabaseURL:        os.Getenv("AILERON_DATABASE_URL"),
		JWTSigningKey:      os.Getenv("AILERON_JWT_SIGNING_KEY"),
		JWTIssuer:          envOrDefault("AILERON_JWT_ISSUER", "aileron"),
		UIRedirectURL:      envOrDefault("AILERON_UI_REDIRECT_URL", "/"),
		AutoVerifyEmail:    os.Getenv("AILERON_AUTO_VERIFY_EMAIL") == "true",
		GoogleClientID:       os.Getenv("GOOGLE_CLIENT_ID"),
		GoogleClientSecret:   os.Getenv("GOOGLE_CLIENT_SECRET"),
		GitHubClientID:       os.Getenv("GITHUB_OAUTH_CLIENT_ID"),
		GitHubClientSecret:   os.Getenv("GITHUB_OAUTH_CLIENT_SECRET"),
		OAuthCallbackBaseURL: os.Getenv("AILERON_OAUTH_CALLBACK_BASE_URL"),
	}

	if raw := os.Getenv("AILERON_TRUSTED_ORIGINS"); raw != "" {
		for _, p := range strings.Split(raw, ",") {
			if p = strings.TrimSpace(p); p != "" {
				cfg.TrustedOrigins = append(cfg.TrustedOrigins, p)
			}
		}
	}

	// Parse durations with defaults.
	var err error
	cfg.AccessTokenTTL, err = parseDurationOrDefault("AILERON_ACCESS_TOKEN_TTL", 15*time.Minute)
	if err != nil {
		return nil, err
	}
	cfg.RefreshTokenTTL, err = parseDurationOrDefault("AILERON_REFRESH_TOKEN_TTL", 7*24*time.Hour)
	if err != nil {
		return nil, err
	}

	// If no database URL is set, auth is disabled — return config as-is.
	if cfg.DatabaseURL == "" {
		return cfg, nil
	}

	// Validate required fields when auth is enabled.
	if cfg.JWTSigningKey == "" {
		return nil, fmt.Errorf("AILERON_JWT_SIGNING_KEY is required when AILERON_DATABASE_URL is set")
	}

	return cfg, nil
}

// AuthEnabled reports whether persistent auth is configured.
func (c *AuthConfig) AuthEnabled() bool {
	return c.DatabaseURL != ""
}

// GoogleEnabled reports whether Google OAuth is configured.
func (c *AuthConfig) GoogleEnabled() bool {
	return c.GoogleClientID != "" && c.GoogleClientSecret != ""
}

// GitHubEnabled reports whether GitHub OAuth is configured.
func (c *AuthConfig) GitHubEnabled() bool {
	return c.GitHubClientID != "" && c.GitHubClientSecret != ""
}

func envOrDefault(key, def string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return def
}

func parseDurationOrDefault(envKey string, def time.Duration) (time.Duration, error) {
	v := os.Getenv(envKey)
	if v == "" {
		return def, nil
	}
	d, err := time.ParseDuration(v)
	if err != nil {
		return 0, fmt.Errorf("invalid %s: %w", envKey, err)
	}
	return d, nil
}

// Package app wires together the Aileron control plane components and exposes
// them as an http.Handler. It is imported by the standalone server binary and
// the MCP server's embedded mode.
package app

import (
	"context"
	"log/slog"
	"net/http"
	"os"
	"time"

	api "github.com/ALRubinger/aileron/core/api/gen"
	"github.com/ALRubinger/aileron/core/approval"
	"github.com/ALRubinger/aileron/core/auth"
	githubauth "github.com/ALRubinger/aileron/core/auth/github"
	googleauth "github.com/ALRubinger/aileron/core/auth/google"
	"github.com/ALRubinger/aileron/core/config"
	"github.com/ALRubinger/aileron/core/connector"
	googlecalendar "github.com/ALRubinger/aileron/core/connector/calendar/google"
	"github.com/ALRubinger/aileron/core/connector/git/github"
	"github.com/ALRubinger/aileron/core/connector/payments/stripe"
	"github.com/ALRubinger/aileron/core/notify"
	"github.com/ALRubinger/aileron/core/policy"
	mcpreg "github.com/ALRubinger/aileron/core/registry"
	"github.com/ALRubinger/aileron/core/store/mem"
	"github.com/ALRubinger/aileron/core/store/postgres"
	"github.com/ALRubinger/aileron/core/vault"
	"github.com/google/uuid"
)

// NewHandler creates a fully-wired Aileron control plane HTTP handler with
// in-memory stores, seeded policies, and registered connectors.
func NewHandler(log *slog.Logger) (http.Handler, error) {
	ctx := context.Background()

	// --- In-memory stores ---
	intentStore := mem.NewIntentStore()
	approvalStore := mem.NewApprovalStore()
	policyStore := mem.NewPolicyStore()
	grantStore := mem.NewGrantStore()
	executionStore := mem.NewExecutionStore()
	connectorStore := mem.NewConnectorStore()
	mcpServerStore := mem.NewMCPServerStore()
	credentialStore := mem.NewCredentialStore()
	fundingSourceStore := mem.NewFundingSourceStore()
	traceStore := mem.NewTraceStore()

	// --- Connector registry ---
	registry := connector.NewRegistry()
	registry.Register(ctx, stripe.New())
	registry.Register(ctx, googlecalendar.New())
	registry.Register(ctx, github.New())

	// --- Vault ---
	v := vault.NewMemVault()
	if token := os.Getenv("GITHUB_TOKEN"); token != "" {
		v.Put(ctx, "connectors/github/default", []byte(token), vault.Metadata{
			Type: "api_key",
			Labels: map[string]string{
				"connector": "github",
			},
		})
		log.Info("seeded GitHub token into vault")
	}

	// --- Policy engine ---
	policyEngine := policy.NewRuleEngine(policyStore)

	if err := policy.SeedPolicies(ctx, policyStore); err != nil {
		return nil, err
	}
	log.Info("seeded default policies")

	// --- Approval orchestrator ---
	idGen := func() string { return uuid.New().String() }
	orchestrator := approval.NewInMemoryOrchestrator(approvalStore, idGen)

	// --- MCP Registry client ---
	registryClient := mcpreg.NewClient(nil, log)
	if interval := os.Getenv("REGISTRY_REFRESH_INTERVAL"); interval != "" {
		if d, err := time.ParseDuration(interval); err == nil {
			registryClient = registryClient.WithRefreshInterval(d)
			log.Info("registry refresh interval overridden", "interval", d)
		} else {
			log.Warn("invalid REGISTRY_REFRESH_INTERVAL, using default", "value", interval, "error", err)
		}
	}
	registryClient.Start(ctx)

	// --- Notifier ---
	notifier := notify.NewLogNotifier(log)

	// --- HTTP handler ---
	mux := http.NewServeMux()

	server := &apiServer{
		log:            log,
		registry:       registry,
		policyEngine:   policyEngine,
		orchestrator:   orchestrator,
		vault:          v,
		notifier:       notifier,
		intents:        intentStore,
		approvals:      approvalStore,
		policies:       policyStore,
		grants:         grantStore,
		executions:     executionStore,
		connectors:     connectorStore,
		mcpServers:     mcpServerStore,
		registryClient: registryClient,
		credentials:    credentialStore,
		fundingSources: fundingSourceStore,
		traces:         traceStore,
		newID:          idGen,
	}
	api.HandlerFromMux(server, mux)

	registerDocsRoutes(mux)

	// --- Auth (optional — enabled when AILERON_DATABASE_URL is set) ---
	authCfg, err := config.LoadAuthConfig()
	if err != nil {
		return nil, err
	}

	// Middleware chain: CORS -> request ID -> logging -> [auth] -> routes.
	var handler http.Handler = mux

	if authCfg.AuthEnabled() {
		db, err := postgres.NewDB(ctx, authCfg.DatabaseURL)
		if err != nil {
			return nil, err
		}
		log.Info("connected to PostgreSQL")

		enterpriseStore := postgres.NewEnterpriseStore(db)
		userStore := postgres.NewUserStore(db)
		sessionStore := postgres.NewSessionStore(db)
		verificationCodeStore := postgres.NewVerificationCodeStore(db)

		// Wire stores into apiServer for /me endpoints.
		server.enterprises = enterpriseStore
		server.users = userStore

		tokenIssuer := auth.NewTokenIssuer(
			[]byte(authCfg.JWTSigningKey),
			authCfg.JWTIssuer,
			authCfg.AccessTokenTTL,
		)

		authRegistry := auth.NewRegistry()
		if authCfg.GoogleEnabled() {
			authRegistry.Register(googleauth.New(
				authCfg.GoogleClientID,
				authCfg.GoogleClientSecret,
			))
			log.Info("registered Google OAuth provider")
		}
		if authCfg.GitHubEnabled() {
			authRegistry.Register(githubauth.New(
				authCfg.GitHubClientID,
				authCfg.GitHubClientSecret,
			))
			log.Info("registered GitHub OAuth provider")
		}

		enforcer := auth.NewStoreEnforcer(enterpriseStore)

		mailer := auth.NewLogMailer(log)

		authHandler := auth.NewHandler(auth.HandlerConfig{
			Log:               log,
			Registry:          authRegistry,
			Enforcer:          enforcer,
			Issuer:            tokenIssuer,
			Users:             userStore,
			Enterprises:       enterpriseStore,
			Sessions:          sessionStore,
			VerificationCodes: verificationCodeStore,
			Mailer:            mailer,
			NewID:             idGen,
			UIRedirect:        authCfg.UIRedirectURL,
			RefreshTTL:        authCfg.RefreshTokenTTL,
			AutoVerifyEmail:   authCfg.AutoVerifyEmail,
			CallbackBaseURL:   authCfg.OAuthCallbackBaseURL,
			TrustedOrigins:    authCfg.TrustedOrigins,
		})
		authHandler.RegisterRoutes(mux)

		skipPaths := map[string]bool{
			"/v1/health": true,
		}
		handler = auth.Middleware(tokenIssuer, skipPaths)(handler)
		log.Info("auth middleware enabled")
	}

	handler = loggingMiddleware(log, handler)
	handler = requestIDMiddleware(handler)
	handler = corsMiddleware(handler)

	return handler, nil
}

